SELECT id, title, content, publisher_id AS publisherId, publisher_name AS publisherName, publish_time AS publishTime, status, is_deleted AS isDeleted, create_time AS createTime, update_time AS updateTime FROM notice
is_deleted = 0
AND title LIKE concat('%', #{title}, '%')
AND publisher_id = #{publisherId}
AND publisher_name LIKE concat('%', #{publisherName}, '%')
AND status = #{status}
AND publish_time >= #{startTime}
AND publish_time <= #{endTime}
ORDER BY publish_time DESC
LIMIT #{current}, #{size}

